t.script:
    (function() {
        'use strict';

        // ── MAP INIT ────────────────────────────────────────────────
        var map = L.map('live-map', {
            zoomControl: true,
            attributionControl: true,
        }).setView([23.7701, 90.4254], 12);

        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
            attribution: '© OpenStreetMap',
            maxZoom: 19,
        }).addTo(map);

        var markers = {};
        var allLatLngs = [];

        // Status colors
        var statusColors = {
            live:    '#059669',
            idle:    '#D97706',
            offline: '#94A3B8',
        };

        function makeIcon(status, initials) {
            var bg = status === 'live' ? '#16A34A' : '#EAB308';
            var pulse = status === 'live'
                ? ''
                : '';

            var svg = ''
                + pulse
                + ''
                + '' + initials + ''
                + '';

            return L.divIcon({
                html:        svg,
                iconSize:    [42, 42],
                iconAnchor:  [21, 21],
                popupAnchor: [0, -22],
                className:   'x-marker',
            });
        }

        function loadMap() {
            fetch('/salesperson/dashboard/data')
                .then(function(r) { return r.json(); })
                .then(function(data) {
                    if (!data.ok) return;

                    // Clear old markers
                    Object.values(markers).forEach(function(m) { map.removeLayer(m); });
                    markers = {};
                    allLatLngs = [];

                    data.trackers.forEach(function(t) {
                        if (!t.lat || !t.lng) return;
                        allLatLngs.push([t.lat, t.lng]);

                        var icon = makeIcon(t.status, t.initials);
                        var m = L.marker([t.lat, t.lng], { icon: icon })
                            .bindPopup(
                                '
'
                                + '
' + (t.name || '') + ''
                                + '
' + (t.location || '—') + ''
                                + '
'
                                + ''
                                + t.status.charAt(0).toUpperCase() + t.status.slice(1)
                                + ''
                                + '' + t.covered + '/' + t.total + ' visits'
                                + ''
                            )
                            .addTo(map);
                        markers[t.id] = m;
                    });

                    if (allLatLngs.length === 1) {
                        map.setView(allLatLngs[0], 14);
                    } else if (allLatLngs.length > 1) {
                        map.fitBounds(L.latLngBounds(allLatLngs), { padding: [50, 50] });
                    }

                    setTimeout(function() { map.invalidateSize(); }, 200);
                })
                .catch(function(e) { console.warn('Map load error:', e); });
        }

        // ── CSS for pulse animation ──
        var styleEl = document.createElement('style');
        styleEl.textContent = '@keyframes pulse-ring { 0%{transform:scale(1);opacity:.5} 100%{transform:scale(2);opacity:0} }';
        document.head.appendChild(styleEl);

        // Initial load
        loadMap();

        // Auto-refresh every 30s
        setInterval(loadMap, 30000);

        // Public refresh function
        window.dashRefreshMap = function() { loadMap(); };

    })();
